19	//! Batch assay — runs parse + detection pipeline on HTML files, writes
20	//! guillemet-delimited assay output showing PHI classifications inline.
21	//! Usage: cargo run --bin apcab <input-directory>
22	
23	// RCG output discipline: all emission via apcrl_*! — no direct println!/eprintln!
24	
25	use apcd::apcrd_dictionaries::apcrd_Dictionaries;
26	use apcd::apcre_engine::{apcre_analyze, apcre_Result};
27	use apcd::apcrm_match::{apcrm_Finding, apcrm_PhiCategory, apcrm_Severity};
28	
29	fn main() {
30	    let args: Vec<String> = std::env::args().collect();
31	    if args.len() != 2 {
32	        apcd::apcrl_fatal_now!("usage: apcab <input-directory>");
33	    }
34	    let input_dir = &args[1];
35	
36	    let output_dir = std::env::var("BURD_OUTPUT_DIR")
37	        .unwrap_or_else(|_| apcd::apcrl_fatal_now!("BURD_OUTPUT_DIR not set"));
38	
39	    let entries: Vec<_> = std::fs::read_dir(input_dir)
40	        .unwrap_or_else(|e| apcd::apcrl_fatal_now!("failed to read directory {}: {}", input_dir, e))
41	        .filter_map(|entry| {
42	            let entry = entry.ok()?;
43	            let path = entry.path();
44	            if path.extension().and_then(|e| e.to_str()) == Some("html") {
45	                Some(path)
46	            } else {
47	                None
48	            }
49	        })
50	        .collect();
51	
52	    if entries.is_empty() {
53	        apcd::apcrl_fatal_now!("no .html files found in {}", input_dir);
54	    }
55	
56	    apcd::apcrl_info_now!("loading dictionaries");
57	    let dicts = apcrd_Dictionaries::apcrd_load();
58	
59	    let mut processed = 0u32;
60	    for path in &entries {
61	        let stem = path.file_stem()
62	            .and_then(|s| s.to_str())
63	            .unwrap_or("unknown");
64	
65	        apcd::apcrl_info_now!("processing: {}", path.display());
66	
67	        let html = std::fs::read_to_string(path)
68	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!("failed to read {}: {}", path.display(), e));
69	
70	        let result = apcre_analyze(&html, &dicts);
71	
72	        let assay_text = match result {
73	            apcre_Result::Clinical { findings, plain_text } => {
74	                zapcab_render_assay(&plain_text, &findings)
75	            }
76	            apcre_Result::NonClinical { content_type, preview, .. } => {
77	                format!("[non-clinical content: {} — {}]\n", content_type, preview)
78	            }
79	        };
80	
81	        let output_path = std::path::Path::new(&output_dir).join(format!("{}.assay.txt", stem));
82	        std::fs::write(&output_path, &assay_text)
83	            .unwrap_or_else(|e| apcd::apcrl_fatal_now!(
84	                "failed to write {}: {}", output_path.display(), e
85	            ));
86	
87	        apcd::apcrl_info_now!("wrote {} ({} bytes)", output_path.display(), assay_text.len());
88	        processed += 1;
89	    }
90	
91	    apcd::apcrl_info_now!("batch assay complete — {} files processed", processed);
92	}
93	
94	fn zapcab_render_assay(plain_text: &str, findings: &[apcrm_Finding]) -> String {
95	    let mut sorted: Vec<&apcrm_Finding> = findings.iter().collect();
96	    sorted.sort_by_key(|f| (f.offset, std::cmp::Reverse(f.length)));
97	
98	    let mut result = String::with_capacity(plain_text.len() * 2);
99	    let mut pos = 0;
100	
101	    for finding in &sorted {
102	        if finding.offset < pos {
103	            continue;
104	        }
105	
106	        if finding.offset > pos {
107	            result.push_str(&plain_text[pos..finding.offset]);
108	        }
109	
110	        let severity_tag = zapcab_severity_tag(finding.severity);
111	        let category_tag = zapcab_category_tag(finding.category);
112	        let matched_text = &plain_text[finding.offset..finding.offset + finding.length];
113	
114	        result.push('\u{2039}'); // ‹
115	        result.push_str(severity_tag);
116	        result.push(':');
117	        result.push_str(category_tag);
118	        result.push(' ');
119	        result.push_str(matched_text);
120	        result.push('\u{203A}'); // ›
121	
122	        pos = finding.offset + finding.length;
123	    }
124	
125	    if pos < plain_text.len() {
126	        result.push_str(&plain_text[pos..]);
127	    }
128	
129	    result
130	}
131	
132	fn zapcab_severity_tag(severity: apcrm_Severity) -> &'static str {
133	    match severity {
134	        apcrm_Severity::Red    => "RED",
135	        apcrm_Severity::Yellow => "YELLOW",
136	        apcrm_Severity::Pass   => "PASS",
137	    }
138	}
139	
140	fn zapcab_category_tag(category: apcrm_PhiCategory) -> &'static str {
141	    match category {
142	        apcrm_PhiCategory::Name         => "NAME",
143	        apcrm_PhiCategory::Provider     => "PROVIDER",
144	        apcrm_PhiCategory::Facility     => "FACILITY",
145	        apcrm_PhiCategory::Date         => "DATE",
146	        apcrm_PhiCategory::Dob          => "DOB",
147	        apcrm_PhiCategory::Phone        => "PHONE",
148	        apcrm_PhiCategory::Email        => "EMAIL",
149	        apcrm_PhiCategory::Ssn          => "SSN",
150	        apcrm_PhiCategory::Mrn          => "MRN",
151	        apcrm_PhiCategory::Account      => "ACCOUNT",
152	        apcrm_PhiCategory::EncounterId  => "ENCOUNTER_ID",
153	        apcrm_PhiCategory::Address      => "ADDRESS",
154	        apcrm_PhiCategory::HealthPlanId => "HEALTH_PLAN_ID",
155	        apcrm_PhiCategory::DeviceId     => "DEVICE_ID",
156	        apcrm_PhiCategory::Npi          => "NPI",
157	        apcrm_PhiCategory::Dea          => "DEA",
158	        apcrm_PhiCategory::Url          => "URL",
159	        apcrm_PhiCategory::IpAddress    => "IP_ADDRESS",
160	    }
161	}
