15	//! Logging infrastructure — severity-named macros with auto file/line capture.
16	//!
17	//! All application logging goes through `apcrl_*_now!`, `apcrl_*_if!`, and
18	//! comparison variants. No naked `println!`/`eprintln!` elsewhere in the codebase.
19	//!
20	//! Output is line-oriented to stdout. Format:
21	//!   `[LEVEL] [file:line] message`
22	//!
23	//! Suffix families:
24	//!   `_now`  — unconditional emission
25	//!   `_if`   — boolean conditional, returns the bool
26	//!   `_eq`, `_ne`, `_lt`, `_gt`, `_le`, `_ge` — comparison conditional,
27	//!            stringifies arguments, returns the bool
28	
29	pub const APCRL_LEVEL_TRACE: &str = "[TRACE]";
30	pub const APCRL_LEVEL_INFO:  &str = "[INFO]";
31	pub const APCRL_LEVEL_ERROR: &str = "[ERROR]";
32	pub const APCRL_LEVEL_FATAL: &str = "[FATAL]";
33	
34	#[doc(hidden)]
35	pub fn zapcrl_emit(level: &str, file: &str, line: u32, msg: &str) {
36	    println!("{} [{}:{}] {}", level, file, line, msg);
37	}
38	
39	#[doc(hidden)]
40	pub fn zapcrl_emit_fatal(file: &str, line: u32, msg: &str) -> ! {
41	    println!("{} [{}:{}] {}", APCRL_LEVEL_FATAL, file, line, msg);
42	    std::process::exit(1);
43	}
44	
45	// ============================================================
46	// Unconditional (_now)
47	// ============================================================
48	
49	#[macro_export] macro_rules! apcrl_trace_now {
50	    ($($arg:tt)*) => { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!($($arg)*)) };
51	}
52	#[macro_export] macro_rules! apcrl_info_now {
53	    ($($arg:tt)*) => { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_INFO, file!(), line!(), &format!($($arg)*)) };
54	}
55	#[macro_export] macro_rules! apcrl_error_now {
56	    ($($arg:tt)*) => { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!($($arg)*)) };
57	}
58	#[macro_export] macro_rules! apcrl_fatal_now {
59	    ($($arg:tt)*) => { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!($($arg)*)) };
60	}
61	
62	// ============================================================
63	// Boolean conditional (_if)
64	// ============================================================
65	
66	#[macro_export] macro_rules! apcrl_trace_if {
67	    ($cond:expr, $($arg:tt)*) => {{ let z = $cond; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!($($arg)*)); } z }};
68	}
69	#[macro_export] macro_rules! apcrl_error_if {
70	    ($cond:expr, $($arg:tt)*) => {{ let z = $cond; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!($($arg)*)); } z }};
71	}
72	#[macro_export] macro_rules! apcrl_fatal_if {
73	    ($cond:expr, $($arg:tt)*) => { if $cond { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!($($arg)*)); } };
74	}
75	
76	// ============================================================
77	// Trace comparison variants
78	// ============================================================
79	
80	#[macro_export] macro_rules! apcrl_trace_eq {
81	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl == *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!("{}: {} ({:?}) == {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
82	}
83	#[macro_export] macro_rules! apcrl_trace_ne {
84	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl != *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!("{}: {} ({:?}) != {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
85	}
86	#[macro_export] macro_rules! apcrl_trace_lt {
87	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl < *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!("{}: {} ({:?}) < {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
88	}
89	#[macro_export] macro_rules! apcrl_trace_gt {
90	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl > *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!("{}: {} ({:?}) > {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
91	}
92	#[macro_export] macro_rules! apcrl_trace_le {
93	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl <= *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!("{}: {} ({:?}) <= {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
94	}
95	#[macro_export] macro_rules! apcrl_trace_ge {
96	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl >= *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!("{}: {} ({:?}) >= {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
97	}
98	
99	// ============================================================
100	// Error comparison variants
101	// ============================================================
102	
103	#[macro_export] macro_rules! apcrl_error_eq {
104	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl == *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!("{}: {} ({:?}) == {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
105	}
106	#[macro_export] macro_rules! apcrl_error_ne {
107	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl != *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!("{}: {} ({:?}) != {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
108	}
109	#[macro_export] macro_rules! apcrl_error_lt {
110	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl < *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!("{}: {} ({:?}) < {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
111	}
112	#[macro_export] macro_rules! apcrl_error_gt {
113	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl > *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!("{}: {} ({:?}) > {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
114	}
115	#[macro_export] macro_rules! apcrl_error_le {
116	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl <= *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!("{}: {} ({:?}) <= {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
117	}
118	#[macro_export] macro_rules! apcrl_error_ge {
119	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); let z = *zl >= *zr; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!("{}: {} ({:?}) >= {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } z }};
120	}
121	
122	// ============================================================
123	// Fatal comparison variants
124	// ============================================================
125	
126	#[macro_export] macro_rules! apcrl_fatal_eq {
127	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); if *zl == *zr { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!("{}: {} ({:?}) == {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } }};
128	}
129	#[macro_export] macro_rules! apcrl_fatal_ne {
130	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); if *zl != *zr { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!("{}: {} ({:?}) != {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } }};
131	}
132	#[macro_export] macro_rules! apcrl_fatal_lt {
133	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); if *zl < *zr { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!("{}: {} ({:?}) < {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } }};
134	}
135	#[macro_export] macro_rules! apcrl_fatal_gt {
136	    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); if *zl > *zr { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!("{}: {} ({:?}) > {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } }};
137	}
138	#[macro_export] macro_rules! apcrl_fatal_le {
