        .unwrap_or_else(|e| apcd::apcrl_fatal_now!(
            "failed to read directory {}: {}", input_dir, e
        ))
        .filter_map(|entry| {
            let entry = entry.ok()?;
            let path = entry.path();
            if path.extension().and_then(|e| e.to_str()) == Some("html") {
                Some(path)
            } else {
                None
            }
        })
        .collect();

