// ---------------------------------------------------------------------------
// BIO decoder — tokens with identical entity kind get merged to a span.
// Special tokens ([CLS], [SEP], [PAD]) have offsets (0, 0) from the tokenizer
// and are skipped. We treat "O" and malformed labels as boundaries.
// ---------------------------------------------------------------------------

fn zapcnsa_decode_bio(
    labels: &[&str],
    offsets: &[(usize, usize)],
) -> Vec<apcnsa_Finding> {
    let mut findings = Vec::new();
    let mut cur_kind:  Option<String> = None;
    let mut cur_start: usize = 0;
    let mut cur_end:   usize = 0;

    let flush = |cur_kind: &Option<String>, start: usize, end: usize, out: &mut Vec<apcnsa_Finding>| {
        if let Some(k) = cur_kind {
            if end > start {
                out.push(apcnsa_Finding {
                    offset: start,
                    length: end - start,
                    label:  k.clone(),
                });
            }
        }
    };

    for (i, &label) in labels.iter().enumerate() {
        let (tok_start, tok_end) = offsets[i];
        // Skip special tokens — offsets (0,0) and not at the legitimate start of content.
        // Legitimate offset-zero tokens (e.g., first real token of the line) still have
        // tok_end > 0, so the (0,0) test is safe.
        if tok_start == 0 && tok_end == 0 {
            continue;
        }

        if label == "O" {
            flush(&cur_kind, cur_start, cur_end, &mut findings);
            cur_kind = None;
            continue;
        }

        // Labels look like "B-NAME", "I-NAME", or occasionally just "NAME".
        let (tag, kind) = match label.split_once('-') {
            Some((t, k)) => (t, k.to_string()),
            None         => ("B", label.to_string()),
        };

